
<template>
  <div>
    <loader :is-visible="isLoading"></loader>
 
  <tg-list
    :IsShowAction="true"
    :showCheckBox="true"
    ModuleName="CRM"
    SubModuleCode="CRM_CONTACTS"
    IdentityColumn="contact_id"
    :HeaderText="$t('Contact')"
    v-on:ApplyView="OnApplyView" :ViewList="ViewList"
                ref="tgList" 
    :ListData="ContactData"
    :HeaderData="Headers"
    :HeaderButtons="listheaderbuttons"
    :TotalRecords="TotalRecords"
    :SearchFields="leftSearchFields"
    :RenderRowActionMethod="renderActions"
    :ListDataCallBackFunction="FetchData"
    :IsFilterApplied="searchCondition?true:false"
    :LegendArray="LegendArray"
    :SortExp="SortExp"
    :SortBy="SortBy"
    :NorecordfoundText="$t('NoRecordfound')"
    :CurrentPageNumber="PageNumber"
    v-on:LeftsearchButtonClick="leftCommonSearch"
    v-on:PagerButtonClick="pagerMethod"
    v-on:HeaderButtonClick="commonHeaderButtonClick"
    v-on:ActionButtonClick="actionButtonClick"
    v-on:SortdataButtonClick="sortdata">
    <template v-slot:slotdata="{data}">
      <template v-if="data.column.COLUMN_NAME == 'status_id'">
        <listing-status
          isfor="CRM_CONTACTS" 
         v-if="isCRMShowStausDrop(data.row.status_id, 'CRM_CONTACTS')"
          ref="updatestatus"
          v-bind:dataid="data.row.contact_id"
          data-controller="Crm"
          v-bind:statuslist="StatusListForListing"
          v-bind:item="data"
          data-action="index"
         v-bind:dataselected="data.row.status_id"
          v-bind:callbackfunction="FetchData"
          v-bind:isselectedvaluestring="true"
        
        ></listing-status>
        <a
          class="inactive-disabled"
          v-if="!isCRMShowStausDrop(data.row.status_id, 'CRM_CONTACTS')"
        >
          <span
            v-bind:class="getStatusClass(data.row.status_id, 'status_id')"
          >{{data.row[data.column.COLUMN_NAME]}}</span>
        </a>
      </template>
    </template>
  </tg-list>

  <searchfilter
    v-if="showFilter"
    submodulecode="CRM_CONTACTS"
    modulename="CRM"
    v-on:close="showFilter = false"
    v-bind:callbackfunction="FetchData"
    v-on:FilterData="FilterData"
  >
    <h5 slot="header">{{ $t('Search') }}</h5>
  </searchfilter>
  <viewlayout
    v-if="ShowManageView"
    v-show="ShowManageView"
    submodulecode="CRM_CONTACTS"
    modulename="CRM"
    v-on:close="ShowManageView = false"
    v-bind:callbackfunction="FetchData"
    :usertype="usertype"
  >
    <h5 slot="header">{{ $t('Search') }}</h5>
  </viewlayout>
</div>
</template>
<script>
import LeadDataService from "../../../services/DataService";
import searchfilter from "../../../components/Common/Modal/search-filter.vue";
import viewlayout from "../../../components/Common/Modal/view-layout.vue";
import Schema from "../../CRM/Contacts/ContactListingSchema";
export default {
  components: {
    viewlayout,
    LeadDataService,
    searchfilter
   },
  data() {
    return {
      ViewListId:'',
      ViewList:[],
      isLoading: false,
      ShowManageView: false,
      ContactData: null,
      ShowManageView: false,
      Headers: null,
      TotalRecords: 0,
      PageNumber: 1,
      PageSize: 10,
      SortBy: "",
      SortExp: "",
      PageSizeOption: null,
      CurrentPage: 1,
      TotalPages: 0,
      GroupStart: 1,
      GroupEnd: 3,
      firstNameId: "",
      jobTitleId: "",
      buisnessPhoneId: "",
      Status: "",
      showFilter: false,
      NameSearch: "",
      ContactEmail: "",
      PhoneNum: "",
      searchCondition: "",
      noRecord: false,
      IsAnySearch: false,
      userid: null,
      usertype: null,
      companyId: null,
      conditionForInstantSearch: "",
      leftSearchFields: Schema.leftsearchSchema,
      listheaderbuttons: Schema.buttons,
      listActions: Schema.listActions,
      appliedFilter: [],
      StatusListForListing: [],
      LegendArray: [],
      privilegeParams: null
    };
  },
  created: function () {
    this.userid = this.GetUserInfo.ID;
    this.usertype = this.GetUserInfo.UserType;
    this.companyId = this.GetUserInfo.CompanyId;
    this.privilegeParams = `controller=CRM&action=`;
    var ths = this;
    ths.getStatuslistForListing("CRMContract", "en");
    this.FetchData();
    this.GetDdlRecords_ViewList();
    this.GetPageSizeOption();
  },
  methods: {
    GetDdlRecords_ViewList: async function () {
            var vm = this;
            vm.ViewList=[];
            var url = `moduleName=CRM&subModuleCode=CRM_CONTACTS&viewId=0&pageSize=100&pageNum=1&sortBy=&sortExp=`;
            await LeadDataService.GetViewList(url).then(function (response) {   
                if(response.data && typeof(response.data.DATA) != 'undefined'){
                    vm.ViewList = response.data.DATA;
                }
                var chkVACTIVE = 0;
                vm.ViewListId = "0";
                if (vm.ViewList == null || vm.ViewList == "") {
                   
                }
                else {
                    vm.ViewList.forEach(function (item) {

                        if (item.IS_SLECTED_USER_ID > 0) {
                            chkVACTIVE = chkVACTIVE + 1;
                            vm.ViewListId = item.VIEW_ID;
                        }
                    });
                }
                var indx = 0;
                if (chkVACTIVE > 0) {
                    vm.ViewList.splice(indx, 0, { "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 0, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });
                }
                else {
                    if (vm.ViewList == null || vm.ViewList == "") {

                        vm.ViewList.push({ "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 1, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });
                    }
                    else {
                        vm.ViewList.splice(indx, 0, { "SUB_MODULE_NAME": "", "SUB_MODULE_CODE": "", "VIEW_NAME": "Default View", "VIEW_ID": 0, "IS_APPLICABLE_TO_ALL": 1, "MODULE_NAME": "", "CREATED_AT": "", "IS_SLECTED_USER_ID": 1, "CAN_EDIT": 0, "ROWNUMBER": 0, "VIEW_TYPE": "", "USER_LIST": "" });

                    }
                }
                setTimeout(() => {
                    if( vm.ViewListId > 0){
                        vm.$refs.tgList.$refs.tgListHeaderButtons.ViewListId = vm.ViewListId;    
                    }else{
                        vm.$refs.tgList.$refs.tgListHeaderButtons.ViewListId = "0";
                    }
                }, 1000);  
                                
            });           
        }, 
        DefaultView: function () {  
                                            
            var vm = this;
            var obj = {
                ModuleName: 'CRM',
                SubmoduleCode: 'CRM_CONTACTS'
            };            
            var objectPostString = JSON.stringify(obj);
            LeadDataService.ClearView(objectPostString).then(function (response) {
                if (response.data != null) {
                    if (response.data.code == "1" || response.data.Code == "1") {
                        vm.ShowAlert(vm.$t("ClearSuccess", [vm.$t("DefaultView")]), 'success', true, vm.$t('Alert'));
                        //vm.$emit('RefreshManageView');
                        vm.FetchData();
                    }
                    else {
                        vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), 'failure', true, vm.$t('Alert'));
                    }
                }
                else {
                    vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"), 'failure', true, vm.$t('Alert'));
                }
            });
        },
        OnApplyView(viewId) {  
                    
            var vm = this;
            if (viewId == '0') {
                vm.DefaultView()
            }
            else {
                var obj = {
                    ViewId: viewId,
                    ModuleName: 'CRM',
                    SubmoduleCode: 'CRM_CONTACTS'
                };
                var objectPostString = JSON.stringify(obj);                     
                LeadDataService.ApplyView(objectPostString).then(function (response) {
                    if (response.data != null) {
                        if (response.data.code == "1" || response.data.Code == "1") {
                            vm.ShowAlert(vm.$t("ApplySuccess", [vm.$t("View")]), 'success', true, vm.$t('Alert'));
                            vm.$emit('RefreshManageView');
                            vm.FetchData();
                        }
                        else {
                            vm.ShowAlert(vm.$t("AddedError", [vm.$t("View")]), 'failure', true, vm.$t('Alert'));
                        }
                    }
                    else {
                        vm.ShowAlert(vm.$t("AddedError", [vm.$t("View")]), 'failure', true, vm.$t('Alert'));
                    }
                });

            }
        },
        actionButtonClick: function (callbackfunction, item, index, event) {            
            switch (callbackfunction) {    
                case 'Delete':
                  this.commonDeleteData(item.contact_id);
                break;
            }
        },
    renderActions: function (row) {
      var self = this;
      let rtnActionArray = [];
      self.listActions.forEach((actionItem) => {
        let action = { ...actionItem };
        switch (action.title) {
          case "View":
          case "Edit":
          case "Delete":
          default: 
            action.isVisible = true;
            break;
        }
        rtnActionArray.push(action);
      });
      return rtnActionArray;
    },
    clickEventOfColumn: function (row, column) {
      if (column.COLUMN_NAME == "first_name" || column.COLUMN_NAME == "View") {
        this.$router.push({
          path:
            "/CRM/ViewContactDetails/" + row.contact_id + "/CRM/CRM_CONTACTS",
        });
      }
      if (column.COLUMN_NAME == "Edit") {
        this.$router.push({
          path: "/CRM/Manage/" + row.contact_id + "/CRM/CRM_CONTACTS",
        });
      }
    },
    commonHeaderButtonClick: function (event) {
      switch (event.callbackfunction) {
        case "downloadExceldata":
          this.FetchData(true);
          break;
        case "ManageView":
          this.ManageView();
          break;
        case "openFilterPopUp":
          this.openFilterPopUp();
          break;

        case "commonDeleteData":
          this.commonDeleteData();
          break;
        case "removeFilter":
          var ths = this;
                        ths.searchCondition = '';
                        const removeFilterindex= ths.listheaderbuttons.findIndex(object => {
                        return object.callbackfunction === 'removeFilter';});
                        ths.listheaderbuttons[removeFilterindex].isvisible=false;
                        const openFilterPopUpindex= ths.listheaderbuttons.findIndex(object => {
                        return object.callbackfunction === 'openFilterPopUp';});
                        ths.listheaderbuttons[openFilterPopUpindex].iconClass='fa fa-filter';
                         try {
                            ths.appliedFilter = [];
                         } catch (e) { };
                         ths.FetchData();
                        break; 
                        case "setTourGuideSteps":
                    this.setTourGuideSteps(0);
                        break;
      }
    },
    pagerMethod: function (value) {
      this.PageSize = value.PageSize;
      this.PageNumber = value.PageNumber;
      this.FetchData();
    },
    leftCommonSearch: function (value) {
      this.PageNumber = value.PageNumber;
      const parts = value.searchConditionJson.split('=');
      const SearchType = parts[0];
      const phoneNumber = parts[1];
      if (SearchType=='MOBILE_PHONE') {
        this.isPaged = 1;
      if (typeof value.searchCondition != "undefined") {
        var data = '';
        data += "(REPLACE(CONT.MOBILE_PHONE,' ', '') LIKE '%25" + phoneNumber + "%25' OR ";
        data += "REPLACE(CONT.BUSINESS_PHONE,' ', '') LIKE '%25" + phoneNumber + "%25' ) ";
        this.searchCondition = data;
      } else {
        this.searchCondition = "";
      }
      }else{
        this.isPaged = 1;
      if (typeof value.searchCondition != "undefined") {
        this.searchCondition = value.searchCondition;
      } else {
        this.searchCondition = "";
      }
      }
      this.FetchData();
    },
    ManageView: function () {
      var vm = this;
      vm.ShowManageView = true;
      setTimeout(function () {
        $("#modalManageView").modal("show");
        setTimeout(function () {
          vm.SetBootstraptoolTip();
        }, 200);
      }, 1000);
    },
    checkPrivilegeLayout(e) {},
    checkPrivilegeManage(e) {},
    checkPrivilegeView(e) {},
    checkPrivilegeImport: function (e) {
      window.location.href = "/CRM/ImportContacts?reqfrom=/CRM/ContactListing";
    },
    SetCurrentPage: function (pageNumber) {
      this.PageNumber = pageNumber;
      if (pageNumber > this.GroupEnd || pageNumber == 1) {
        this.GroupStart = pageNumber;
        this.GroupEnd = pageNumber + 2;
      } else if (pageNumber < this.GroupStart && pageNumber > 1) {
        this.GroupEnd = this.GroupStart - 1;
        this.GroupStart = pageNumber - 2;
      }
      this.FetchData();
    },
    sortdata: function (sortBy) {
      this.SortBy = sortBy;
      var sortExp = "ASC";
      if (this.SortExp == "ASC") {
        sortExp = "DESC";
      }
      this.SortExp = sortExp;
      this.GroupStart = this.PageNumber;
      this.GroupEnd = this.PageNumber + 2;
      this.FetchData();
    },
    SetPageSize: function (event) {
      this.PageSize = event.target.value;
      this.PageNumber = 1;
      this.GroupStart = this.PageNumber;
      this.GroupEnd = this.PageNumber + 2;
      this.FetchData();
    },
    Searchdata: function (event) {
      var vueObj = this;
      vueObj.PageNumber = 1;
      vueObj.GroupStart = vueObj.PageNumber;
      vueObj.GroupEnd = vueObj.PageNumber + 2;
      vueObj.conditionForInstantSearch = "";
      vueObj.IsAnySearch = false;
      if ($.trim(vueObj.ContactEmail) != "") {
        vueObj.IsAnySearch = true;
        vueObj.conditionForInstantSearch +=
          $.trim(vueObj.conditionForInstantSearch) != "" ? " AND" : "";
        vueObj.conditionForInstantSearch +=
          " CONT.email_id LIKE '%25" + vueObj.ContactEmail + "%25'";
      }
      if ($.trim(vueObj.NameSearch) != "") {
        vueObj.IsAnySearch = true;
        vueObj.conditionForInstantSearch +=
          $.trim(vueObj.conditionForInstantSearch) != "" ? " AND" : "";
        vueObj.conditionForInstantSearch +=
          " (CONT.FIRST_NAME LIKE '%25" + vueObj.NameSearch + "%25' OR ";
        vueObj.conditionForInstantSearch +=
          " CONT.LAST_NAME LIKE '%25" + vueObj.NameSearch + "%25' ) ";
      }
      if ($.trim(vueObj.PhoneNum) != "") {
        vueObj.IsAnySearch = true;
        vueObj.conditionForInstantSearch +=
          $.trim(vueObj.conditionForInstantSearch) != "" ? " AND" : "";
        vueObj.conditionForInstantSearch +=
          " (CONT.MOBILE_PHONE LIKE '%25" + vueObj.PhoneNum + "%25' OR ";
        vueObj.conditionForInstantSearch +=
          " CONT.BUSINESS_PHONE LIKE '%25" + vueObj.PhoneNum + "%25' ) ";
      }
      vueObj.FetchData();
    },
    cancelOrRefresh: function () {
      this.NameSearch = "";
      this.ContactEmail = "";
      this.PhoneNum = "";
      this.searchCondition = "";
      this.IsAnySearch = false;
      this.firstNameId = "";
      this.jobTitleId = "";
      this.buisnessPhoneId = "";
      this.FetchData();
    },
    FilterData: function (
      pageNum,
      pageSize,
      sortBy,
      sortExp,
      searchcondition,
      filterItemData
    ) {
      this.pageNum = pageNum;
      this.pageSize = pageSize;
      this.sortBy = sortBy;
      this.sortExp = sortExp;
      this.searchCondition = searchcondition;
      if (typeof filterItemData != null)
        this.appliedFilter.push(filterItemData);
      this.FetchData();
    },
    GetLocalizedValue: function (fieldName, displayName) {
      if (this.isBlank(displayName)) {
        var chk = this.$t(String(fieldName).toUpperCase());
        if (chk || /^\s*$/.test(chk)) {
          return chk;
        }
        chk = this.$t(String(fieldName));
        if (chk || /^\s*$/.test(chk)) {
          return chk;
        }
        return fieldName;
      } else {
        var chk = this.$t(String(displayName).toUpperCase());
        if (chk || /^\s*$/.test(chk)) {
          return chk;
        }
        chk = this.$t(String(displayName));
        if (chk || /^\s*$/.test(chk)) {
          return chk;
        }
        return displayName;
      }
    },
    FetchData: function (downloadExceldata) {
      this.getStatuslistForListing("CRMContract", "en");
      var vm = this;
      vm.isLoading = true;
      var params;
      if (downloadExceldata) {
        params =
          "pageSize=" +
          this.TotalRecords +
          "&pageNumber=" +
          this.PageNumber +
          "&sortBy=" +
          this.SortBy +
          "&sortExp=" +
          this.SortExp +
          "&StatusID=" +
          this.Status +
          "&First_Name=" +
          this.firstNameId +
          "&job_title=" +
          this.jobTitleId +
          "&business_phone=" +
          this.buisnessPhoneId;
      } else {
        params =
          "pageSize=" +
          this.PageSize +
          "&pageNumber=" +
          this.PageNumber +
          "&sortBy=" +
          this.SortBy +
          "&sortExp=" +
          this.SortExp +
          "&StatusID=" +
          this.Status +
          "&First_Name=" +
          this.firstNameId +
          "&job_title=" +
          this.jobTitleId +
          "&business_phone=" +
          this.buisnessPhoneId;
      }
      var srchCondition = "";
      if (!this.isBlank(this.searchCondition)) {
        srchCondition = srchCondition + this.searchCondition;
      }
      if (!this.isBlank(this.conditionForInstantSearch)) {
        srchCondition =
          srchCondition +
          (!this.isBlank(this.searchCondition)
            ? " AND " + this.conditionForInstantSearch
            : this.conditionForInstantSearch);
      }
      if (srchCondition != "") {
        params = params + "&searchCondition=" + srchCondition;
        if(vm.appliedFilter.length>0){
                const removeFilterindex= vm.listheaderbuttons.findIndex(object => {
                return object.callbackfunction === 'removeFilter';
                });          
                vm.listheaderbuttons[removeFilterindex].isvisible=true;      
                const openFilterPopUpindex= vm.listheaderbuttons.findIndex(object => {
                return object.callbackfunction === 'openFilterPopUp';
                });
                vm.listheaderbuttons[openFilterPopUpindex].iconClass='fa fa-filter text-success';
            }
      }
      else{
                if(vm.appliedFilter.length==0){
                const removeFilterindex= vm.listheaderbuttons.findIndex(object => {
                return object.callbackfunction === 'removeFilter';
                });          
                vm.listheaderbuttons[removeFilterindex].isvisible=false;      
                const openFilterPopUpindex= vm.listheaderbuttons.findIndex(object => {
                return object.callbackfunction === 'openFilterPopUp';
                });
                vm.listheaderbuttons[openFilterPopUpindex].iconClass='fa fa-filter';
            }
          }
      // if (downloadExceldata) {
      //   LeadDataService.ContactListing(params).then(function (response) {
      //     if (response.data != null) {
      //       $.each(response.data.schema, function (i) {
      //         $.each(response.data.schema[i], function () {
      //           response.data.schema[i].DISPLAY_NAME = response.data.schema[
      //             i
      //           ].COLUMN_NAME.replace(/_/g, " ");
      //         });
      //       });
      //       vm.JSONToCSVConvertor(response.data, "Contact-Detail", true);
      //     } else {
      //       vm.ModelnoRecord = true;
      //     }
      //     vm.isLoading = false;
      //   });
      // }
      if(downloadExceldata){
        LeadDataService.ContactListing(params).then(function (response) {
          vm.isLoading = false;
          // Collect the selected lead IDs from the checked checkboxes
          var selectedIds = [];
          $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
              selectedIds.push($(this).val());
          });

          // Check if there are selected IDs and response data is not empty
          if (response.data && response.data.data && response.data.data.length > 0 && selectedIds.length > 0) {
              // Filter the response data's 'data' array to only include selected lead_ids
              var filteredData = response.data.data.filter(function (contact) {
                  return selectedIds.includes(contact.contact_id.toString());
              });

              // If there is filtered data, replace it in response.data and pass it to CSV converter
              if (filteredData.length > 0) {
                  // Keep the schema and other properties intact, and replace only the 'data' array
                  var dataToExport = {
                      ...response.data,  // Spread to copy existing properties
                      data: filteredData  // Replace the data array with the filtered data
                  };

                  // Now pass the properly structured data to the CSV converter
                  vm.JSONToCSVConvertor(dataToExport, "Contact-Detail", true);
              } else {
                vm.ModelnoRecord = true;
              }
          }
          else if (response.data != "" && response.data != null) {
            $.each(response.data.schema, function (i) {
                    $.each(response.data.schema[i], function () {
                      response.data.schema[i].DISPLAY_NAME = response.data.schema[
                        i
                      ].COLUMN_NAME.replace(/_/g, " ");
                    });
                  });
                  vm.JSONToCSVConvertor(response.data, "Contact-Detail", true);
              }
          else {
            vm.ModelnoRecord = true; 
          }
      })
      .catch(function (error) {
          console.log("Error fetching contact listing: ", error);
          vm.isLoading = false;
      });
      }
      else {
        LeadDataService.ContactListing(params).then(function (response) {
          vm.isLoading = false;
          if (response.data != null && response.data!='') {
            vm.Headers = response.data.schema;
            vm.Headers.forEach((column) => {
              column.DISPLAY_NAME= vm.$t(column.DISPLAY_NAME ? column.DISPLAY_NAME : column.COLUMN_NAME);
              column.settings = null;
              if (column.COLUMN_NAME == "first_name") {
                column.settings = {
                  clickEvent: vm.clickEventOfColumn,
                  formatter: vm.columnDataFormatter,
                };
              }
              if (column.COLUMN_NAME == "status_id") {
                column.settings = {
                  isInSlot: true,
                };
              }
            });
            if (response.data.data.length > 0) {
              vm.ContactData = response.data.data;
              vm.ContactData.forEach((row)=>{
              row.rowDetailsUrl='';
                if(row.rowDetailsUrl=='')
                {
                    row.rowDetailsUrl='/CRM/ViewContactDetails/'+row.contact_id+'/CRM/CRM_CONTACTS';
                }
              });
              vm.TotalRecords = response.data.data[0].total_records;
              vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
              vm.CurrentPage = vm.PageNumber;
              vm.noRecord = false;
              vm.GetDdlRecords_ViewList();
              vm.listheaderbuttons[6].isdisabled=true;
            } else {
              vm.noRecord = true;
              vm.ContactData = [];
              vm.TotalRecords = 0;
            }
          } else {
            vm.noRecord = true;
            vm.ContactData = [];
            vm.Headers = [];
            vm.TotalRecords = 0;
          }
          vm.isLoading = false;
        });
      }
    },

    unescape: function (name) {
      if (name != null) {
        var newname = unescape(name);
        return newname;
      }
    },
    GetPageSizeOption: function () {
      var list = [];
      var defaultPageSize = 10;
      for (var i = defaultPageSize; i < defaultPageSize + 95; i += 5) {
        list.push(i);
      }
      this.PageSizeOption = list;
    },
    openFilterPopUp(source_id) {
      this.showFilter = true;
    },
    commonDeleteData: function (event) {
      var vm = this;
      LeadDataService.CheckPrivilege(vm.privilegeParams+'DeleteContact')
                        .then(function (response) { 
                                       
                          if (response.data) {
                            var val = "";
                            if(event== undefined){
                              $(".chkItems:checkbox:checked")
                              .not("[id^='chkAll']")
                              .each(function () {
                                if (val.length > 0) val += ",";
                                val += $(this).val();
                              });
                            }else{
                              val=event;
                            }
                         
                            if (val.length > 0 || event>0) {
                              vm.confirmR(
                                vm.$t("ConfirmDelete"),
                                true,
                                vm.$t("Delete") + "  " + vm.$t("Contacts"),
                                function () {
                                  var postJSON = {
                                    ids: val,
                                    moduleName: "CRM",
                                    subModuleCode: "CRM_CONTACTS",
                                  };
                                  var objectPostString = JSON.stringify(postJSON);
                                  LeadDataService.deleteActivityData(objectPostString).then(function (
                                    response
                                  ) {
                                    if (response.data[0].Status == "Success") {
                                      
                                 vm.ShowAlert(
                                        vm.$t("DeletedSuccess", [vm.$t("Contacts")]),
                                        "Success",
                                        true,
                                        vm.$t("Alert")
                                      );
                                      vm.PageNumber = parseInt(vm.PageNumber) - 1;
                                      if (vm.PageNumber <= 0) {
                                        vm.PageNumber = 1;
                                      }
                                      vm.FetchData();
                                    } else {
                                     vm.ShowAlert(
                                        vm.$t("DeletedError", [vm.$t("Contacts")]),
                                        "failure",
                                        true,
                                        vm.$t("Alert")
                                      );
                                    }
                                  });
                                }
                              );
                            } else {
                              alert(vm.$t("Selectanyrecordtodelete"));
                            }
                          }
                          else {
                            vm.ShowAlert('You are not authorized', "failure", true, "Alert");
                          }

  });
    },
    getStatuslistForListing: function (StatusType, lang) {
      var vm = this;
      var url =
        "langCode=" + lang + "&statusType=" + StatusType + "&hasglobal=true";
      LeadDataService.statusdropdown(url).then(function (response) {
        if (response.data.status == "Success") {
          var json = response.data.result;
          vm.StatusListForListing = json.data;
        }
      });
    },
  },
};
</script>
